USE rb_note;
CREATE TABLE IF NOT EXISTS rb_note (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, title VARCHAR(200) NOT NULL DEFAULT '', content TEXT, image VARCHAR(500) DEFAULT '', `like` INT DEFAULT 0, collection INT DEFAULT 0, comment INT DEFAULT 0, type VARCHAR(50) DEFAULT '', time VARCHAR(50) DEFAULT '', address VARCHAR(200) DEFAULT '', create_time DATETIME DEFAULT CURRENT_TIMESTAMP, update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_like (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, note_id BIGINT NOT NULL, create_time DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uk_user_note (user_id, note_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_collection (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, note_id BIGINT NOT NULL, create_time DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uk_user_note (user_id, note_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_note_browse (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, note_id BIGINT NOT NULL, create_time DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_topic (id BIGINT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(100) NOT NULL UNIQUE, create_time DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rb_note_topic (id BIGINT AUTO_INCREMENT PRIMARY KEY, note_id BIGINT NOT NULL, topic_id BIGINT NOT NULL, create_time DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT IGNORE INTO rb_note (id, user_id, title, content, image, `like`, collection, type) VALUES (1, 1, '分享我家的装修风格！超喜欢这个飘窗设计', '最近刚装修完，飘窗是我最满意的部分', 'https://picsum.photos/300/400?random=1', 1700, 200, '家居'), (2, 1, '三口之家的幸福时光', '周末带娃去公园，记录下这些美好的瞬间', 'https://picsum.photos/300/500?random=2', 3200, 500, '生活'), (3, 1, '美妆分享｜让皮肤变好的秘密', '坚持用了三个月，皮肤真的变好了', 'https://picsum.photos/300/420?random=6', 1800, 250, '美妆');
